WITH left_counts AS (  SELECT {0} AS k, COUNT(*) AS left_count FROM {1}   WHERE {2} IS NOT NULL GROUP BY {3}), right_counts AS (  SELECT {4} AS k, COUNT(*) AS right_count FROM {5}   WHERE {6} IS NOT NULL GROUP BY {7}) SELECT COALESCE(SUM(left_count * right_count), 0) AS estimated_join_rows, COALESCE(SUM(CASE WHEN left_count > 1 THEN 1 ELSE 0 END), 0) AS left_duplicate_values, COALESCE(SUM(CASE WHEN right_count > 1 THEN 1 ELSE 0 END), 0) AS right_duplicate_values FROM left_counts JOIN right_counts USING(k)
